const items = $input.all();
return items.map(item => {
  const j = item.json || {};
  const phone = (j.phone === undefined || j.phone === null) ? '' : String(j.phone).trim();
  const msgId = (j.msgId === undefined || j.msgId === null) ? '' : String(j.msgId).trim();
  const convId = (j.chatwoot_conversation_id === undefined || j.chatwoot_conversation_id === null) ? '' : String(j.chatwoot_conversation_id).trim();
  const contactId = (j.chatwoot_contact_id === undefined || j.chatwoot_contact_id === null) ? '' : String(j.chatwoot_contact_id).trim();
  const normalizedText = (j.normalized_text === undefined || j.normalized_text === null) ? '' : String(j.normalized_text);
  let safetyFlags = j.safety_flags;
  if (typeof safetyFlags === 'string') {
    try { safetyFlags = JSON.parse(safetyFlags); } catch (e) { safetyFlags = {}; }
  }
  if (!safetyFlags || typeof safetyFlags !== 'object' || Array.isArray(safetyFlags)) safetyFlags = {};
  const clinical = safetyFlags.clinical === true;
  const sensitiveImage = safetyFlags.sensitive_image === true;
  const paymentProof = safetyFlags.payment_proof === true;
  const shouldHandoff = j.should_handoff === true || j.should_handoff === 'true';
  const handoffReason = (j.handoff_reason === undefined || j.handoff_reason === null) ? '' : String(j.handoff_reason);
  const fragmentsCount = (typeof j.fragments_count === 'number') ? j.fragments_count : (parseInt(j.fragments_count, 10) || 1);
  const testRunId = (j.test_run_id === undefined || j.test_run_id === null) ? '' : String(j.test_run_id);
  const isCompliance = shouldHandoff || clinical || sensitiveImage || paymentProof;
  let resolvedHandoffReason = handoffReason;
  if (!resolvedHandoffReason || resolvedHandoffReason === '') {
    if (clinical) resolvedHandoffReason = 'documento_clinico_sensivel';
    else if (sensitiveImage) resolvedHandoffReason = 'imagem_sensivel';
    else if (paymentProof) resolvedHandoffReason = 'comprovante_pagamento';
    else if (shouldHandoff) resolvedHandoffReason = 'safety_flag_generic';
  }
  const allowRealRaw = (typeof process !== 'undefined' && process.env && process.env.ALLOW_REAL_WHATSAPP_SEND) ? String(process.env.ALLOW_REAL_WHATSAPP_SEND).toLowerCase() : 'false';
  const dryRunRaw = (typeof process !== 'undefined' && process.env && process.env.IGOR_DRY_RUN) ? String(process.env.IGOR_DRY_RUN).toLowerCase() : 'true';
  const allowReal = allowRealRaw === 'true';
  const dryRun = dryRunRaw === 'true';
  const shouldSendReal = allowReal && !dryRun;
  let sendGateReason;
  if (shouldSendReal) sendGateReason = 'allow_real_true_and_dry_run_false';
  else if (!allowReal) sendGateReason = 'allow_real_whatsapp_send_not_true';
  else sendGateReason = 'igor_dry_run_true';
  const sessionKey = 'after_hours_' + phone;
  const igor05CompliancePayload = {
    chatwoot_conversation_id: convId,
    chatwoot_contact_id: contactId,
    lead_id: '',
    handoff_reason: resolvedHandoffReason,
    summary: 'Midia/conteudo sensivel detectado pelo normalizer.',
    callback_period: '',
    owner_flow: 'after_hours',
    test_run_id: testRunId,
  };
  return {
    json: {
      phone,
      msg_id: msgId,
      chatwoot_conversation_id: convId,
      chatwoot_contact_id: contactId,
      normalized_text: normalizedText,
      safety_flags: safetyFlags,
      should_handoff: shouldHandoff,
      handoff_reason: resolvedHandoffReason,
      fragments_count: fragmentsCount,
      test_run_id: testRunId,
      _is_compliance: isCompliance,
      _safety_clinical: clinical,
      _safety_sensitive_image: sensitiveImage,
      _safety_payment_proof: paymentProof,
      _allow_real_whatsapp_send: allowReal,
      _igor_dry_run: dryRun,
      _should_send_real: shouldSendReal,
      _send_gate_reason: sendGateReason,
      session_key: sessionKey,
      igor05_compliance_payload: igor05CompliancePayload,
      igor05_compliance_payload_json: JSON.stringify(igor05CompliancePayload),
    },
  };
});

const items = $input.all();
function splitMsg(raw) {
  const s = String(raw || '').trim();
  if (!s) return [];
  let parts;
  if (s.includes('||')) {
    parts = s.split(/\s*\|\|\s*/);
  } else {
    parts = s.split(/\n{2,}/);
  }
  return parts.map(p => p.trim()).filter(p => p.length > 0).slice(0, 4);
}
return items.map(item => {
  const j = item.json || {};
  const raw = (j.output !== undefined && j.output !== null) ? j.output : (j.text || '');
  const messages = splitMsg(raw);
  return { json: { messages, message_count: messages.length, raw_output: raw } };
});
